BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS public.revenue_os_council_agents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),agent_code text NOT NULL UNIQUE,display_name text NOT NULL,run_order integer NOT NULL,status text NOT NULL,execution_mode text NOT NULL DEFAULT 'shadow' CHECK(execution_mode='shadow'),external_actions_enabled boolean NOT NULL DEFAULT false CHECK(external_actions_enabled=false),metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_agent_versions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),agent_code text NOT NULL,version text NOT NULL,prompt_code text NOT NULL,prompt_hash text NOT NULL,status text NOT NULL DEFAULT 'active',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(agent_code,version));
CREATE TABLE IF NOT EXISTS public.revenue_os_council_runs(id uuid PRIMARY KEY,tenant_id text NOT NULL,objective_id uuid NOT NULL,strategy_id uuid NOT NULL,strategy_version text NOT NULL,context_snapshot_id uuid NOT NULL,status text NOT NULL,idempotency_key text NOT NULL,requested_by text NOT NULL,external_actions integer NOT NULL DEFAULT 0 CHECK(external_actions=0),payload jsonb NOT NULL DEFAULT '{}'::jsonb,started_at timestamptz NOT NULL DEFAULT now(),completed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,idempotency_key));
CREATE TABLE IF NOT EXISTS public.revenue_os_council_reviews(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL REFERENCES public.revenue_os_council_runs(id) ON DELETE CASCADE,strategy_id uuid NOT NULL,strategy_version text NOT NULL,agent_code text NOT NULL,status text NOT NULL,provider text NOT NULL,model text NOT NULL,prompt_version text NOT NULL,request_hash text NOT NULL,response_hash text NOT NULL,external_actions integer NOT NULL DEFAULT 0 CHECK(external_actions=0),payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(run_id,agent_code));
CREATE TABLE IF NOT EXISTS public.revenue_os_council_findings(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,review_id uuid NOT NULL,strategy_id uuid NOT NULL,severity text NOT NULL,blocking boolean NOT NULL DEFAULT false,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_evidence_checks(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,review_id uuid NOT NULL,strategy_id uuid NOT NULL,classification text NOT NULL,blocking boolean NOT NULL DEFAULT false,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_contradictions(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,review_id uuid NOT NULL,strategy_id uuid NOT NULL,severity text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_scores(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,run_id uuid NOT NULL,review_id uuid NOT NULL,strategy_id uuid NOT NULL,agent_code text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(run_id,agent_code));
CREATE TABLE IF NOT EXISTS public.revenue_os_council_disagreements(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,strategy_id uuid NOT NULL,status text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_resolutions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,run_id uuid NOT NULL,disagreement_id uuid NOT NULL,status text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_red_team_attacks(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,strategy_id uuid NOT NULL,survived boolean NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_optimization_runs(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,strategy_id uuid NOT NULL,source_version text NOT NULL,optimized_version text NOT NULL,status text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_strategy_corrections(id uuid PRIMARY KEY,tenant_id text NOT NULL,run_id uuid NOT NULL,strategy_id uuid NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_classifications(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,run_id uuid NOT NULL UNIQUE,strategy_id uuid NOT NULL,classification text NOT NULL,ready_for_mz12 boolean NOT NULL DEFAULT false,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_council_audit_events(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,run_id uuid NOT NULL,strategy_id uuid NOT NULL,action text NOT NULL,external_actions integer NOT NULL DEFAULT 0 CHECK(external_actions=0),payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS revenue_os_council_runs_queue_idx ON public.revenue_os_council_runs(status,created_at);
CREATE INDEX IF NOT EXISTS revenue_os_council_reviews_run_idx ON public.revenue_os_council_reviews(tenant_id,run_id,agent_code);
CREATE INDEX IF NOT EXISTS revenue_os_council_findings_block_idx ON public.revenue_os_council_findings(tenant_id,run_id,blocking,severity);
CREATE INDEX IF NOT EXISTS revenue_os_council_classification_idx ON public.revenue_os_council_classifications(tenant_id,classification,ready_for_mz12);
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['revenue_os_council_agents','revenue_os_council_agent_versions','revenue_os_council_runs','revenue_os_council_reviews','revenue_os_council_findings','revenue_os_council_evidence_checks','revenue_os_council_contradictions','revenue_os_council_scores','revenue_os_council_disagreements','revenue_os_council_resolutions','revenue_os_council_red_team_attacks','revenue_os_council_optimization_runs','revenue_os_council_strategy_corrections','revenue_os_council_classifications','revenue_os_council_audit_events'] LOOP EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY',t);EXECUTE format('REVOKE ALL ON public.%I FROM anon, authenticated',t);EXECUTE format('GRANT ALL ON public.%I TO service_role',t);END LOOP;END $$;
INSERT INTO public.revenue_os_council_agents(agent_code,display_name,run_order,status,execution_mode,external_actions_enabled,metadata) VALUES
('chief_revenue_intelligence','Chief Revenue Intelligence Agent',10,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('market_intelligence','Market Intelligence Strategist',20,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('offer_monetization','Offer and Monetization Architect',30,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('sales_conversion','Sales Conversion Strategist',40,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('capacity_delivery','Capacity and Delivery Validator',50,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('revenue_risk_margin','Revenue Risk and Margin Validator',60,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('brand_authority','Brand and Authority Validator',70,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('commercial_red_team','Red-Team Commercial Critic',80,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('executive_optimizer','Executive Strategy Optimizer',90,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini')),
('independent_auditor','Independent Auditor',100,'active','shadow',false,jsonb_build_object('promptVersion','11.0.0','provider','gemini'))
ON CONFLICT(agent_code) DO UPDATE SET display_name=excluded.display_name,run_order=excluded.run_order,status='active',execution_mode='shadow',external_actions_enabled=false,metadata=excluded.metadata,updated_at=now();
INSERT INTO public.revenue_os_council_agent_versions(agent_code,version,prompt_code,prompt_hash,status,metadata) SELECT agent_code,'11.0.0','council-'||agent_code,encode(digest('council-'||agent_code||':11.0.0','sha256'),'hex'),'active',jsonb_build_object('provider','gemini','structuredOutput',true,'externalActions',0) FROM public.revenue_os_council_agents ON CONFLICT(agent_code,version) DO UPDATE SET status='active',metadata=excluded.metadata;
UPDATE public.revenue_os_installations SET release_code='AC-REVENUE-OS-MZ11-VALIDATION-COUNCIL',module_version='11.0.0',execution_mode='shadow',contract_locked=true,external_actions_enabled=false,metadata=coalesce(metadata,'{}'::jsonb)||jsonb_build_object('currentPhase','MZ11','validationCouncil',true,'mandatoryAgents',10,'externalActions',0,'nextPhase','MZ12'),updated_at=now() WHERE installation_key='revenue-command-os';
DO $$ BEGIN IF (SELECT count(*) FROM public.revenue_os_council_agents WHERE status='active')<>10 THEN RAISE EXCEPTION 'MZ11 requires exactly 10 active council agents';END IF;IF EXISTS(SELECT 1 FROM public.revenue_os_council_agents WHERE external_actions_enabled) THEN RAISE EXCEPTION 'MZ11 external action lock violated';END IF;IF NOT EXISTS(SELECT 1 FROM public.revenue_os_installations WHERE installation_key='revenue-command-os' AND release_code='AC-REVENUE-OS-MZ11-VALIDATION-COUNCIL' AND external_actions_enabled=false) THEN RAISE EXCEPTION 'MZ11 installation registry assertion failed';END IF;END $$;
COMMIT;
